  await appendKnowledge(resolveHiveKnowledgePath(), newHiveEntry);
  return `Promoted lesson ${lessonId} from swarm to hive: "${swarmEntry.lesson.slice(0, 50)}${swarmEntry.lesson.length > 50 ? "..." : ""}"`;
