      tier: "swarm",
      lesson: truncateLesson(raw.text),
      category: raw.categoryHint ?? inferCategoryFromText(raw.text),
      tags: [...inferredTags, `migration:${raw.sourceSection}`],
      scope: "global",
      confidence: 0.3,
      status: "candidate",
      confirmed_by: [],
