function containsPathTraversal(str) {
  if (/\.\.[/\\]/.test(str))
    return true;
  if (/(?:^|[/\\])\.\.(?:[/\\]|$)/.test(str))
    return true;
  if (/%2e%2e/i.test(str))
    return true;
  if (/%2e\./i.test(str))
    return true;
  if (/%2e/i.test(str) && /\.\./.test(str))
    return true;
  if (/%252e%252e/i.test(str))
    return true;
  if (/\uff0e/.test(str))
    return true;
  if (/\u3002/.test(str))
    return true;
  if (/\uff65/.test(str))
    return true;
  if (/%2f/i.test(str))
    return true;
  if (/%5c/i.test(str))
    return true;
  return false;
}
function containsControlChars(str) {
  return /[\0\t\r\n]/.test(str);
}

